module tb_RAM;

    // Parameters
    parameter CLK_PERIOD = 10; // Clock period in simulation time units

    // Inputs
    reg clk;
    reg rst_n;
    reg write_en;
    reg [7:0] write_addr;
    reg [5:0] write_data;
    reg read_en;
    reg [7:0] read_addr;

    // Outputs
    wire [5:0] read_data;

    // Instantiate the module
    RAM uut (
        .clk(clk),
        .rst_n(rst_n),
        .write_en(write_en),
        .write_addr(write_addr),
        .write_data(write_data),
        .read_en(read_en),
        .read_addr(read_addr),
        .read_data(read_data)
    );

    // Clock generation
    always #((CLK_PERIOD)/2) clk = ~clk;

    integer error = 0;
    integer total_checks = 0;
    real pass_rate = 0.0;
    // Initial block for stimulus generation
    initial begin
        // Initialize inputs
        clk = 0;
        rst_n = 1;
        repeat(100) begin
            write_en = 0;
            write_addr = 0;
            write_data = 0;
            read_en = 0;
            read_addr = 0;
            // Wait for a few clock cycles
            #((CLK_PERIOD) * 5);
            // Release reset
            rst_n = 0;
            #((CLK_PERIOD) * 2);
            rst_n = 1;
            // Write operation
            write_en = 1;
            write_addr = 3'b000;
            write_data = $random;
            #((CLK_PERIOD) * 1);
            write_en = 0;
            #((CLK_PERIOD) * 1);

            // Read operation
            read_en = 1;
            read_addr = 3'b000;
            #((CLK_PERIOD) * 1);
            // $display("read_data = %b", read_data); 
            total_checks = total_checks + 1;
            if (!(read_data == write_data)) begin
                error = error + 1;
            end
            read_en = 0;
            #((CLK_PERIOD) * 1);
            // $display("read_data = %b", read_data); 
            total_checks = total_checks + 1;
            if (!(read_data == 0)) begin
                error = error + 1;
            end
        end
        if (error == 0) begin

            $display("===========Your Design Passed===========");

        end

        else begin

            pass_rate = (total_checks == 0) ? 0.0 : 100.0 * (total_checks - error) / total_checks;

            $display("===========Test completed with %0d/%0d failures (pass rate = %0.2f%%)===========", error, total_checks, pass_rate);

        end
        // Finish simulation
        $finish;
    end

endmodule

