module tb_valid_ready;


parameter PERIOD  = 10;
reg   clk                                  = 0 ;
reg   rst_n                                = 0 ;
reg   [7:0]  data_in                       = 0 ;
reg   valid_in                             = 0 ;

wire  valid_out                              ;
wire  [9:0]  data_out                       ;


initial
begin
    forever #(PERIOD/2)  clk=~clk;
end

initial
begin
    #(PERIOD*2) rst_n  =  1;
end

accu  uut (
    .clk                     ( clk             ),
    .rst_n                   ( rst_n           ),
    .data_in                 ( data_in   [7:0] ),
    .valid_in                ( valid_in        ),

    .valid_out               ( valid_out       ),
    .data_out                ( data_out  [9:0] )
);

initial
begin
    #(PERIOD*1+0.01); 
    #(PERIOD)   data_in = 8'd1;valid_in = 1;
    #(PERIOD)   data_in = 8'd2;
    #(PERIOD)   data_in = 8'd3;
    #(PERIOD)   data_in = 8'd14;

    #(PERIOD)   data_in = 8'd5;
    #(PERIOD)   data_in = 8'd2;
    #(PERIOD)   data_in = 8'd103;
    #(PERIOD)   data_in = 8'd4;

    #(PERIOD)   data_in = 8'd5;
    #(PERIOD)   data_in = 8'd6;
    #(PERIOD)   data_in = 8'd3;
    #(PERIOD)   data_in = 8'd54;
    #(PERIOD*2);
    $finish;
end

reg [9:0] result [0:2];
initial begin
    result[0] = 9'd20;
    result[1] = 9'd114;
    result[2] = 9'd68;
end

integer i;
integer casenum = 0;
integer error = 0;
integer total_checks = 0;
real pass_rate = 0.0;
integer expected_outputs = 3;
integer missing = 0;

initial
begin
    for (i = 0; i < 15; i = i + 1) begin
        #((PERIOD) * 1);         
        if (valid_out) begin
            total_checks = total_checks + 1;
            if (!(data_out == result[casenum])) begin
                error = error + 1;
            end
            casenum = casenum + 1;
        end        
    end

    if (casenum < expected_outputs) begin
        missing = expected_outputs - casenum;
        total_checks = total_checks + missing;
        error = error + missing;
    end

    if (error == 0 && casenum == expected_outputs) begin
        $display("===========Your Design Passed===========");
    end else begin
        pass_rate = (total_checks == 0) ? 0.0 : 100.0 * (total_checks - error) / total_checks;
        $display("===========Test completed with %0d/%0d failures (pass rate = %0.2f%%)===========", error, total_checks, pass_rate);
    end
    $finish;
end


